INSERT INTO `audit_logs` VALUES (5,'DRAFT','PENDING_REVIEW','2026-04-14 19:41:51',NULL,8,10),(6,'PENDING_REVIEW','DEPT_APPROVED','2026-04-15 01:35:02','Đề tài hoàn thành ở mức độ trung bình khá, chấp nhận thông qua để xét duyệt.',8,13),(7,'DEPT_APPROVED','PENDING_COUNCIL','2026-04-15 12:21:25','Phòng QLKH đã phân công Hội đồng xét duyệt: Hồi đồng xét duyệt số 1. Phiên họp dự kiến: 2026-04-21 tại Phòng họp P.101.',8,2),(8,'DRAFT','PENDING_REVIEW','2026-04-15 20:34:14','Chủ nhiệm đã nộp lại bản giải trình và cập nhật hồ sơ theo yêu cầu.',9,10),(9,'PENDING_REVIEW','DEPT_APPROVED','2026-04-15 20:38:16','Đề tài phù hợp với nhu cầu cấp thiết thực tiễn của xã hội. Cho phép thông qua tiến hành xét duyệt.',9,3),(10,'DEPT_APPROVED','PENDING_COUNCIL','2026-04-15 20:59:58','Đề tài được giao cho Hội đồng xét duyệt: Hội đồng Xét duyệt Chuyên môn Số 1',9,12),(11,'DRAFT','PENDING_REVIEW','2026-04-15 23:40:05',NULL,10,10),(12,'PENDING_REVIEW','DEPT_APPROVED','2026-04-15 23:42:16','Đề tài phù hợp với thị hiếu số hoá tiếp thị sở thích của người dùng trong thi trường giải trí. Chấp nhận thông qua để phê duyệt.',10,3),(13,'DEPT_APPROVED','PENDING_COUNCIL','2026-04-15 23:44:43','Đề tài được giao cho Hội đồng xét duyệt: Hội đồng phê duyệt cấp cơ sở số 02',10,12),(14,'DRAFT','PENDING_REVIEW','2026-04-16 23:16:05',NULL,11,10),(15,'DRAFT','PENDING_REVIEW','2026-04-16 23:48:39',NULL,12,10),(16,'PENDING_REVIEW','DEPT_APPROVED','2026-04-16 23:52:35','ĐỒNG Ý THÔNG QUA ĐỂ XÉT DUYỆT!',11,3),(17,'DEPT_APPROVED','PENDING_COUNCIL','2026-04-16 23:54:57','Đề tài được giao cho Hội đồng xét duyệt: Hội đồng phê duyệt cấp cơ sở số 02',11,12),(18,'DRAFT','PENDING_REVIEW','2026-04-17 00:30:39',NULL,13,10),(19,'PENDING_REVIEW','DEPT_REJECTED','2026-04-17 11:44:03','KHÔNG THÔNG QUA DO BÁO CÁO THUYẾT MINH ĐỀ TÀI KHÔNG TRÌNH BÀY ĐỦ NỘI DUNG PHƯƠNG PHÁP NGHIÊN CỨU',12,3),(20,'DEPT_REJECTED','PENDING_REVIEW','2026-04-17 11:57:56','Chủ nhiệm đã nộp lại bản giải trình và cập nhật hồ sơ theo yêu cầu.',12,10),(21,'PENDING_REVIEW','DEPT_APPROVED','2026-04-17 13:28:10','Đã bổ sung đầy đủ thông tin còn thiếu chấp nhận thông qua.\n',12,3),(22,'DEPT_APPROVED','PENDING_COUNCIL','2026-04-17 13:30:45','Đề tài được giao cho Hội đồng xét duyệt: Hội đồng phê duyệt số 3',12,12),(23,'PENDING_REVIEW','DEPT_REJECTED','2026-04-17 16:05:11','Thiếu file thuyết minh đề tài, yêu cầu bổ sung.',13,3),(24,'DEPT_REJECTED','PENDING_REVIEW','2026-04-17 16:06:17',NULL,13,10),(25,'PENDING_REVIEW','DEPT_REJECTED','2026-04-17 16:06:37','chưa bổ sung đầy đủ',13,3),(26,'DEPT_REJECTED','PENDING_REVIEW','2026-04-17 16:07:34','Chủ nhiệm đã nộp lại bản giải trình và cập nhật hồ sơ theo yêu cầu.',13,10),(27,'PENDING_REVIEW','DEPT_APPROVED','2026-04-17 16:08:05','XÉT DUYỆT\n',13,3),(28,'DEPT_APPROVED','REVISION_REQUIRED','2026-04-17 16:08:55','vẫn còn thiếu các thông tin: tính mới của đề tài, phạm vi nghiên cứu. Yêu cầu bổ sung!\n',13,12),(29,'REVISION_REQUIRED','PENDING_REVIEW','2026-04-17 16:10:19','Chủ nhiệm đã nộp lại bản giải trình và cập nhật hồ sơ theo yêu cầu.',13,10),(30,'PENDING_REVIEW','DEPT_APPROVED','2026-04-17 16:11:01','CHẤP NHẬN NỘI DUNG THIẾU XÓT\n',13,3),(31,'DEPT_APPROVED','PENDING_COUNCIL','2026-04-17 16:12:37','Đề tài được giao cho Hội đồng xét duyệt: HỘI ĐỒNG PHÊ DUYỆT CƠ SỞ SỐ 04',13,12),(32,'PENDING_COUNCIL','REVISION_REQUIRED','2026-04-17 17:42:05','--- TỔNG HỢP Ý KIẾN THÀNH VIÊN ---\n[Chủ tịch - Trần Thị Lan]: Nhìn chung, đề tài này có hướng tiếp cận khá hiện đại khi kết hợp giữa học máy và phân tích hành vi người dùng. Điểm đáng ghi nhận là nhóm đã không chỉ dừng lại ở việc xây dựng mô hình dự đoán mà còn định hướng phát triển thành một hệ thống có khả năng ứng dụng thực tế. Tuy nhiên, để đề tài có tính thuyết phục cao hơn, cần làm rõ hơn về nguồn dữ liệu và cách đánh giá hiệu quả mô hình.\n\n[Phản biện - Phạm Minh Tuấn]: Đề tài có ý tưởng tốt nhưng hiện tại vẫn mang tính định hướng nhiều hơn là thực nghiệm. Một số phần trình bày còn mang tính mô tả, chưa có minh chứng cụ thể bằng số liệu hoặc kết quả thử nghiệm. Nhóm cần bổ sung phần đánh giá định lượng để làm rõ mức độ hiệu quả của mô hình.\n\n[Ủy viên - Vũ Hoàng Anh]: Đây là một đề tài được triển khai tương đối tốt, có sự liên kết rõ ràng giữa các phần từ dữ liệu, mô hình đến hệ thống. Kết quả đạt được có ý nghĩa thực tiễn và cho thấy tiềm năng phát triển thành sản phẩm. Nếu tiếp tục hoàn thiện, đặc biệt là phần giao diện và trải nghiệm người dùng, đề tài hoàn toàn có thể được mở rộng ở mức cao hơn.\n\n[Phản biện - Bùi Thanh Hải]: Môi trường giáo dục đại học và sau đại học: Hệ thống đóng vai trò là nền tảng hạ tầng cốt lõi cho phòng quản lý khoa học công nghệ tại các trường đại học. Phần mềm giúp chuẩn hóa quy trình tiếp nhận, đánh giá và xét duyệt các đề tài nghiên cứu của giảng viên, nghiên cứu sinh và sinh viên. Việc số hóa toàn bộ quá trình chấm điểm độc lập và tự động tổng hợp biên bản giúp minh bạch hóa kết quả học thuật, đồng thời tạo lập cơ sở dữ liệu lưu trữ hồ sơ lịch sử lâu dài.',11,15),(33,'DRAFT','PENDING_REVIEW','2026-04-18 07:46:01',NULL,14,10),(34,'PENDING_REVIEW','DEPT_APPROVED','2026-04-18 07:47:39','Đề tài có tính cấp thiết cao, bám sát các vấn đề thực tiễn của xã hội/ngành công nghiệp hiện nay. Tên đề tài phù hợp với nội dung nghiên cứu.\n',14,13),(35,'DEPT_APPROVED','PENDING_COUNCIL','2026-04-18 07:51:47','Đề tài được giao cho Hội đồng xét duyệt: Hội đồng số 05',14,2),(36,'PENDING_COUNCIL','APPROVED','2026-04-18 11:00:35','--- TỔNG HỢP Ý KIẾN THÀNH VIÊN ---\n[Chủ tịch - Phan Thi Lan]: Ý tưởng nghiên cứu có triển vọng nhưng nội dung thuyết minh còn một số điểm chưa cụ thể, cần làm rõ trước khi phê duyệt chính thức.\n\n\n[Ủy viên - Vũ Hoàng Hải ]: Ý tưởng nghiên cứu có triển vọng nhưng nội dung thuyết minh còn một số điểm chưa cụ thể, cần làm rõ trước khi phê duyệt chính thức.\nCác điểm cần chỉnh sửa:\nPhạm vi nghiên cứu: Đối tượng nghiên cứu hiện tại quá rộng so với thời gian 6 tháng thực hiện. Đề nghị nhóm tác giả khu trú lại phạm vi cụ thể tại một khu vực hoặc một nhóm đối tượng đặc thù.\nSản phẩm dự kiến: Các chỉ số đo lường hiệu quả (KPIs) của sản phẩm phần mềm còn mơ hồ. Cần bổ sung các tiêu chuẩn kỹ thuật cụ thể (ví dụ: thời gian phản hồi, độ chính xác của thuật toán).\nKinh phí: Mục chi cho \"Thuê chuyên gia\" và \"Mua sắm thiết bị\" chưa có báo giá đính kèm, cần bổ sung giải trình chi tiết.\n\n\n[Phản biện - Hoàng Minh Tâm]: Ưu điểm: * Cách tiếp cận vấn đề hiện đại, có sự kế thừa và phát triển từ các nghiên cứu quốc tế.\nPhương pháp nghiên cứu rõ ràng, logic, có tính khả thi cao về mặt kỹ thuật.\nCấu trúc thuyết minh chặt chẽ, văn phong khoa học chuẩn mực.\nGóp ý thêm: Cần làm rõ hơn kế hoạch triển khai thực tế tại các đơn vị phối hợp để đảm bảo tiến độ như cam kết.\n\n\n[Phản biện - Bùi Thanh Hải]: Nhận xét chung: Đề tài có tính cấp thiết cao, bám sát các vấn đề thực tiễn của xã hội/ngành công nghiệp hiện nay. Tên đề tài phù hợp với nội dung nghiên cứu.',14,23);
