INSERT INTO `evaluations` VALUES (5,11.75,22.50,16.25,15.75,15.50,0.00,0.00,81.75,'Đề tài đạt yêu cầu về mặt nội dung và hình thức. Tuy nhiên, cần chú ý phân tích sâu hơn ở các ý chính để đạt được kết quả tối ưu trong lần tới.','APPROVED','SUBMITTED',16,10),(6,10.00,17.50,14.75,15.00,15.00,0.00,0.00,72.25,'Đây là một hướng nghiên cứu mới mẻ, thể hiện sự sáng tạo và tinh thần tìm tòi học hỏi cao của sinh viên/giảng viên. Cách tiếp cận vấn đề độc đáo cùng với những đề xuất giải pháp có tính đột phá là điểm nhấn quan trọng của đề tài. Hội đồng khuyến khích tác giả tiếp tục mở rộng nghiên cứu để công bố trên các tạp chí khoa học uy tín.','APPROVED','SUBMITTED',18,10),(7,12.25,25.00,18.25,17.25,16.25,0.00,0.00,89.00,'Đề tài thể hiện sự đầu tư công phu, nghiêm túc với phương pháp nghiên cứu hiện đại và hệ thống số liệu tin cậy. Kết quả đạt được không chỉ có giá trị cao về mặt lý luận mà còn mang tính thực tiễn sâu sắc, có khả năng ứng dụng rộng rãi vào thực tế chuyên môn. Hội đồng đánh giá cao tư duy phản biện và khả năng giải quyết vấn đề triệt để của nhóm tác giả.','APPROVED','SUBMITTED',19,10),(8,9.75,20.75,14.50,15.75,14.75,0.00,0.00,75.50,'Nội dung nghiên cứu bám sát mục tiêu đề ra, cấu trúc logic và trình bày khoa học. Nhóm tác giả đã nắm vững kiến thức nền tảng và có những đóng góp nhất định trong việc làm rõ vấn đề nghiên cứu. Tuy còn một vài hạn chế nhỏ về phạm vi khảo sát, nhưng tổng thể đây là một công trình có chất lượng tốt, đủ điều kiện để nghiệm thu và phát triển thêm.','APPROVED','SUBMITTED',20,10),(9,13.00,22.25,17.00,16.75,16.50,0.00,0.00,85.50,'Nhìn chung, đề tài này có hướng tiếp cận khá hiện đại khi kết hợp giữa học máy và phân tích hành vi người dùng. Điểm đáng ghi nhận là nhóm đã không chỉ dừng lại ở việc xây dựng mô hình dự đoán mà còn định hướng phát triển thành một hệ thống có khả năng ứng dụng thực tế. Tuy nhiên, để đề tài có tính thuyết phục cao hơn, cần làm rõ hơn về nguồn dữ liệu và cách đánh giá hiệu quả mô hình.','APPROVED','SUBMITTED',16,11),(10,6.25,24.50,5.25,4.25,5.25,0.00,0.00,45.50,'Đề tài có ý tưởng tốt nhưng hiện tại vẫn mang tính định hướng nhiều hơn là thực nghiệm. Một số phần trình bày còn mang tính mô tả, chưa có minh chứng cụ thể bằng số liệu hoặc kết quả thử nghiệm. Nhóm cần bổ sung phần đánh giá định lượng để làm rõ mức độ hiệu quả của mô hình.','REJECTED','SUBMITTED',19,11),(11,7.25,22.75,18.00,14.25,14.00,0.00,0.00,76.25,'Đây là một đề tài được triển khai tương đối tốt, có sự liên kết rõ ràng giữa các phần từ dữ liệu, mô hình đến hệ thống. Kết quả đạt được có ý nghĩa thực tiễn và cho thấy tiềm năng phát triển thành sản phẩm. Nếu tiếp tục hoàn thiện, đặc biệt là phần giao diện và trải nghiệm người dùng, đề tài hoàn toàn có thể được mở rộng ở mức cao hơn.','APPROVED','SUBMITTED',20,11),(12,12.00,20.25,16.00,15.50,16.50,0.00,0.00,80.25,'Môi trường giáo dục đại học và sau đại học: Hệ thống đóng vai trò là nền tảng hạ tầng cốt lõi cho phòng quản lý khoa học công nghệ tại các trường đại học. Phần mềm giúp chuẩn hóa quy trình tiếp nhận, đánh giá và xét duyệt các đề tài nghiên cứu của giảng viên, nghiên cứu sinh và sinh viên. Việc số hóa toàn bộ quá trình chấm điểm độc lập và tự động tổng hợp biên bản giúp minh bạch hóa kết quả học thuật, đồng thời tạo lập cơ sở dữ liệu lưu trữ hồ sơ lịch sử lâu dài.','APPROVED','SUBMITTED',18,11),(13,12.00,23.00,10.00,20.00,20.00,0.00,0.00,85.00,'Ý tưởng nghiên cứu có triển vọng nhưng nội dung thuyết minh còn một số điểm chưa cụ thể, cần làm rõ trước khi phê duyệt chính thức.\n','APPROVED','SUBMITTED',31,14),(14,6.00,19.00,13.75,14.50,16.50,0.00,0.00,69.75,'Ý tưởng nghiên cứu có triển vọng nhưng nội dung thuyết minh còn một số điểm chưa cụ thể, cần làm rõ trước khi phê duyệt chính thức.\nCác điểm cần chỉnh sửa:\nPhạm vi nghiên cứu: Đối tượng nghiên cứu hiện tại quá rộng so với thời gian 6 tháng thực hiện. Đề nghị nhóm tác giả khu trú lại phạm vi cụ thể tại một khu vực hoặc một nhóm đối tượng đặc thù.\nSản phẩm dự kiến: Các chỉ số đo lường hiệu quả (KPIs) của sản phẩm phần mềm còn mơ hồ. Cần bổ sung các tiêu chuẩn kỹ thuật cụ thể (ví dụ: thời gian phản hồi, độ chính xác của thuật toán).\nKinh phí: Mục chi cho \"Thuê chuyên gia\" và \"Mua sắm thiết bị\" chưa có báo giá đính kèm, cần bổ sung giải trình chi tiết.\n','REVISION_REQUIRED','SUBMITTED',35,14),(15,7.50,19.00,17.50,17.25,17.25,0.00,0.00,78.50,'Ưu điểm: * Cách tiếp cận vấn đề hiện đại, có sự kế thừa và phát triển từ các nghiên cứu quốc tế.\nPhương pháp nghiên cứu rõ ràng, logic, có tính khả thi cao về mặt kỹ thuật.\nCấu trúc thuyết minh chặt chẽ, văn phong khoa học chuẩn mực.\nGóp ý thêm: Cần làm rõ hơn kế hoạch triển khai thực tế tại các đơn vị phối hợp để đảm bảo tiến độ như cam kết.\n','APPROVED','SUBMITTED',33,14),(16,8.75,20.50,16.00,16.75,16.75,0.00,0.00,78.75,'Nhận xét chung: Đề tài có tính cấp thiết cao, bám sát các vấn đề thực tiễn của xã hội/ngành công nghiệp hiện nay. Tên đề tài phù hợp với nội dung nghiên cứu.','APPROVED','SUBMITTED',34,14);
