INSERT INTO `topics` VALUES (8,'TOPIC-EF3E8887','Nghiên cứu vật liệu nano trong xử lý nước thải công nghiệp','Study of Nanomaterials in Industrial Wastewater Treatment','EXPERIMENTAL','Y sinh và Sức khỏe cộng đồng','<p>Ô nhiễm vi nhựa trong môi trường biển đang gia tăng nhanh chóng, gây ra những ảnh hưởng nghiêm trọng đến hệ sinh thái và tiềm ẩn rủi ro đối với sức khỏe con người.</p>','<p>Đánh giá toàn diện tác động của vi nhựa đến hệ sinh thái biển và các loài sinh vật sống trong môi trường này.</p>','<ul><li><p>Phân tích mẫu nước và sinh vật biển</p></li><li><p>Xác định mức độ tích tụ vi nhựa</p></li><li><p>Đánh giá ảnh hưởng sinh học và sinh thái</p></li></ul>','<p>Tiếp cận thực nghiệm kết hợp phân tích môi trường nhằm xác định mức độ ô nhiễm vi nhựa và tác động của chúng đến sinh vật biển.</p>','<p>Sử dụng phương pháp lấy mẫu, phân tích hóa học và quan sát sinh học để đánh giá sự hiện diện và ảnh hưởng của vi nhựa.</p>','Các khu vực biển ven bờ và xa bờ tại một số vùng tiêu biểu, tập trung vào các loài sinh vật phổ biến trong chuỗi thức ăn.','<p>Xuất bản 02 bài báo quốc tế về ô nhiễm vi nhựa và 01 báo cáo khoa học tại hội nghị môi trường biển khu vực.</p>','<p>Xây dựng quy trình phân tích và đánh giá mức độ vi nhựa trong môi trường biển có thể áp dụng rộng rãi.</p>',NULL,'<p>Đào tạo 02 học viên thạc sĩ chuyên ngành sinh học biển và hỗ trợ 02 sinh viên tham gia nghiên cứu thực địa.</p>','<p>Khảo sát thực địa, thu thập mẫu, phân tích trong phòng thí nghiệm và tổng hợp kết quả để đưa ra kết luận khoa học.</p>',24,1200000000.00,'2026-04-14 19:41:17','PENDING_COUNCIL',2,10,4,4,0),(9,'TOPIC-93EDA148','Nghiên cứu và ứng dụng các mô hình học máy trong xây dựng hệ thống đánh giá rủi ro tín dụng đối với doanh nghiệp nhỏ và vừa (SME) tại Việt Nam','A Study on the Application of Machine Learning Techniques for Credit Risk Assessment of Small and Medium Enterprises (SMEs) in Vietnam','BASIC','Công nghệ thông tin và Trí tuệ nhân tạo','--- GIẢI TRÌNH CHỈNH SỬA ---\nBổ sung file thuyết minh đề tài còn thiếu trong quá trình nhập.\n\n--- NỘI DUNG ---\n<p>Trong bối cảnh nền kinh tế Việt Nam ngày càng phụ thuộc nhiều vào khu vực doanh nghiệp nhỏ và vừa, nhu cầu tiếp cận vốn của nhóm doanh nghiệp này tăng mạnh nhưng quá trình xét duyệt tín dụng vẫn còn phụ thuộc đáng kể vào phương pháp truyền thống. Các phương pháp truyền thống thường dựa trên kinh nghiệm của cán bộ tín dụng, báo cáo tài chính lịch sử và một số chỉ số định tính, do đó có thể bỏ sót các tín hiệu rủi ro tiềm ẩn hoặc đánh giá chưa đầy đủ khả năng trả nợ của doanh nghiệp.</p>','<p>Xây dựng và đánh giá một hệ thống đánh giá rủi ro tín dụng cho doanh nghiệp nhỏ và vừa tại Việt Nam dựa trên các mô hình học máy, nhằm hỗ trợ quá trình thẩm định và ra quyết định tín dụng một cách chính xác, nhanh chóng và có khả năng ứng dụng thực tế.</p>','<p>Thu thập, chuẩn hóa và làm sạch dữ liệu doanh nghiệp từ nhiều nguồn khác nhau.<br>Phân tích đặc điểm dữ liệu, xác định các biến có ảnh hưởng đến khả năng vỡ nợ hoặc chậm thanh toán.<br>Xây dựng, so sánh và lựa chọn mô hình học máy phù hợp để dự đoán rủi ro tín dụng.<br>Đánh giá mô hình bằng các thước đo định lượng như Accuracy, Precision, Recall, F1-score, ROC-AUC.<br>Đề xuất quy trình ứng dụng mô hình vào thực tiễn đánh giá tín dụng cho tổ chức tài chính hoặc ngân hàng.</p>','<ul><li><p>Những nhóm biến nào có ảnh hưởng lớn nhất đến khả năng rủi ro tín dụng của doanh nghiệp SME?</p></li><li><p>Mô hình học máy nào cho hiệu quả dự báo tốt nhất trên bộ dữ liệu nghiên cứu?</p></li><li><p>Có thể xây dựng một quy trình đánh giá rủi ro tín dụng tự động, đơn giản và có khả năng triển khai thực tế hay không?</p></li><li><p>Hệ thống đề xuất có cải thiện được tính khách quan và tốc độ xử lý so với phương pháp truyền thống hay không?</p></li></ul>','<p>Đề tài sử dụng phương pháp nghiên cứu định lượng kết hợp phân tích dữ liệu. Quy trình nghiên cứu bao gồm thu thập dữ liệu, tiền xử lý, phân tích mô tả, xây dựng đặc trưng, huấn luyện mô hình và đánh giá mô hình.</p>','1. Đối tượng nghiên cứu\nDoanh nghiệp nhỏ và vừa tại Việt Nam có nhu cầu vay vốn hoặc đã từng phát sinh lịch sử tín dụng tại các tổ chức tài chính.\n2. Phạm vi nghiên cứu\nDữ liệu được thu thập trong giai đoạn từ 2019 đến 2025.\nPhạm vi ngành ưu tiên gồm: thương mại, sản xuất, dịch vụ và logistics.\nNghiên cứu tập trung vào dữ liệu cấu trúc, không bao gồm phân tích văn bản phi cấu trúc ở giai đoạn đầu.\nKết quả mô hình chỉ phục vụ mục đích nghiên cứu và mô phỏng, không thay thế quy trình phê duyệt tín dụng thực tế của tổ chức tài chính.','<p>Báo cáo tổng kết đề tài</p>','<p>Mô hình thử nghiệm hỗ trợ đánh giá rủi ro tín dụng</p>','<p>Thu thập dữ liệu mua dữ liệu, tổng hợp nguồn, lưu trữ: 5.000.000</p><p>Phần mềm và công cụ, bản quyền, công cụ phân tích: 5.000.000</p><p>In ấn và tài liệu in báo cáo, tài liệu tham khảo: 5.000.000</p><p>Hội thảo, họp nhóm trao đổi, phản biện, góp ý: 10.000.000</p><p>Hỗ trợ nghiên cứu chi phí thực hiện, phân tích, kiểm thử: 5.000.000</p>',NULL,'<h2>Giai đoạn 1: Khảo sát và thu thập dữ liệu</h2><p>Xác định nguồn dữ liệu phù hợp, bao gồm dữ liệu tài chính doanh nghiệp, thông tin ngành nghề, lịch sử thanh toán, quy mô doanh nghiệp và một số biến mô tả hoạt động kinh doanh. Đồng thời khảo sát các công trình nghiên cứu trong và ngoài nước về chấm điểm tín dụng và dự báo rủi ro.</p><h2>Giai đoạn 2: Làm sạch và tiền xử lý dữ liệu</h2><p>Loại bỏ dữ liệu trùng lặp, xử lý giá trị thiếu, phát hiện và xử lý ngoại lệ, chuyển đổi kiểu dữ liệu, mã hóa biến phân loại và chuẩn hóa các biến số để phù hợp với mô hình học máy.</p><h2>Giai đoạn 3: Phân tích và lựa chọn đặc trưng</h2><p>Phân tích mối quan hệ giữa biến đầu vào và biến mục tiêu. Lọc ra các đặc trưng có ý nghĩa, loại bỏ biến nhiễu hoặc biến không có giá trị dự báo. Từ đó xây dựng bộ đặc trưng tối ưu cho mô hình.</p><h2>Giai đoạn 4: Xây dựng mô hình</h2><p>Huấn luyện nhiều mô hình khác nhau để so sánh hiệu năng. Điều chỉnh siêu tham số nhằm cải thiện độ chính xác và khả năng tổng quát hóa. Đánh giá hiện tượng quá khớp và cân bằng giữa độ chính xác và khả năng diễn giải.</p><h2>Giai đoạn 5: Đánh giá và đề xuất ứng dụng</h2><p>So sánh kết quả giữa các mô hình, xác định mô hình tối ưu, sau đó xây dựng quy trình ứng dụng mô hình vào thực tế. Đề xuất giao diện hoặc pipeline triển khai thử nghiệm cho bộ phận thẩm định tín dụng.</p>',12,30000000.00,'2026-04-15 20:31:41','PENDING_COUNCIL',2,10,2,1,0),(10,'TOPIC-1AB45EBE','Nghiên cứu và phát triển hệ thống gợi ý nội dung giải trí theo trạng thái cảm xúc người dùng dựa trên dữ liệu hành vi và mô hình học máy','An Emotion-Aware Content Recommendation System Based on User Behavioral Data and Machine Learning','APPLIED','Công nghệ thông tin và Trí tuệ nhân tạo','<p>Người dùng hiện nay tiêu thụ nội dung giải trí với tần suất cao, nhưng trải nghiệm cá nhân hóa vẫn chưa thực sự tối ưu do thiếu yếu tố cảm xúc. Một người có thể thích phim hành động, nhưng khi đang mệt mỏi lại muốn nội dung nhẹ nhàng hơn. Việc không hiểu được trạng thái cảm xúc tức thời khiến hệ thống gợi ý chưa đạt hiệu quả tối đa.</p><p>Do đó, việc xây dựng một hệ thống có khả năng suy đoán cảm xúc từ hành vi và đưa ra gợi ý phù hợp sẽ giúp nâng cao trải nghiệm người dùng và mở ra hướng phát triển mới cho các nền tảng nội dung số.</p>','<p>Xây dựng hệ thống gợi ý nội dung (phim, nhạc, video) dựa trên trạng thái cảm xúc suy ra từ hành vi người dùng.</p>','<ul><li><p>Xây dựng mô hình suy đoán cảm xúc từ hành vi</p></li><li><p>Xây dựng hệ thống recommender theo emotion</p></li><li><p>So sánh với recommender truyền thống</p></li><li><p>Phát triển demo web/app</p></li></ul>','<ul><li><p>Có thể suy ra cảm xúc từ hành vi số không?</p></li><li><p>Những hành vi nào phản ánh rõ nhất cảm xúc?</p></li><li><p>Emotion-aware recommendation có tốt hơn traditional không?</p></li><li><p>Có thể triển khai realtime không?</p></li></ul>','<h2>Tiền xử lý dữ liệu</h2><ul><li><p>Xử lý missing values</p></li><li><p>Chuẩn hóa dữ liệu</p></li><li><p>Encoding</p></li></ul><h2>Feature Engineering</h2><ul><li><p>Session-based features</p></li><li><p>Behavioral patterns</p></li><li><p>Temporal features</p></li></ul><h2>Xây dựng mô hình</h2><h3>Giai đoạn 1: Emotion Classification</h3><ul><li><p>Logistic Regression</p></li><li><p>Random Forest</p></li><li><p>XGBoost</p></li><li><p>Neural Network</p></li></ul><h3>Giai đoạn 2: Recommendation</h3><ul><li><p>Content-Based</p></li><li><p>Collaborative Filtering (ALS)</p></li><li><p>Hybrid Model</p></li></ul>','Đối tượng nghiên cứu: Người dùng các nền tảng nội dung số (phim, video, âm nhạc)\n\nPhạm vi nghiên cứu\nDữ liệu hành vi người dùng trong môi trường số\nNội dung gợi ý: phim hoặc video\nDữ liệu có thể là:\nDataset công khai (MovieLens)\nDữ liệu mô phỏng hành vi\nKhông sử dụng dữ liệu nhạy cảm như hình ảnh, giọng nói','<p>Báo cáo</p>','<p>Mô hình học máy</p>',NULL,NULL,'<ul><li><p>Thu thập dữ liệu</p></li><li><p>Làm sạch dữ liệu</p></li><li><p>Feature engineering</p></li><li><p>Huấn luyện mô hình cảm xúc</p></li><li><p>Xây dựng recommender</p></li><li><p>Tích hợp hệ thống</p></li><li><p>Đánh giá</p></li></ul>',12,50000000.00,'2026-04-15 23:39:58','APPROVED',2,10,2,5,0),(11,'TOPIC-CE857A9E','Nghiên cứu và phát triển hệ thống dự đoán và tối ưu hóa chất lượng không khí đô thị dựa trên dữ liệu cảm biến và mô hình học máy','A Machine Learning-Based System for Air Quality Prediction and Optimization in Smart Cities Using IoT Sensor Data','BASIC','Công nghệ thông tin và Trí tuệ nhân tạo','<p>Ô nhiễm không khí đang trở thành một trong những vấn đề nghiêm trọng tại các đô thị lớn, đặc biệt ở các quốc gia đang phát triển. Chất lượng không khí kém ảnh hưởng trực tiếp đến sức khỏe con người, gây ra các bệnh về hô hấp, tim mạch và làm giảm chất lượng sống.</p><p>Hiện nay, các hệ thống giám sát chất lượng không khí chủ yếu chỉ dừng lại ở việc <strong>quan sát (monitoring)</strong> mà chưa có khả năng <strong>dự đoán (prediction)</strong> và <strong>tối ưu (optimization)</strong> một cách chủ động. Ngoài ra, dữ liệu cảm biến từ các trạm đo thường phân tán, chưa được khai thác hiệu quả bằng các mô hình học máy.</p>','<p>Xây dựng hệ thống dự đoán và hỗ trợ tối ưu chất lượng không khí đô thị dựa trên dữ liệu cảm biến và mô hình học máy.</p>','<ul><li><p>Thu thập và tích hợp dữ liệu từ nhiều nguồn cảm biến</p></li><li><p>Xây dựng mô hình dự đoán chỉ số AQI</p></li><li><p>Phân tích các yếu tố ảnh hưởng đến ô nhiễm không khí</p></li><li><p>Xây dựng hệ thống cảnh báo sớm</p></li><li><p>Đề xuất các phương án tối ưu hóa</p></li></ul>','<ol><li><p>Những yếu tố nào ảnh hưởng lớn nhất đến chất lượng không khí đô thị?</p></li><li><p>Có thể dự đoán AQI chính xác trong ngắn hạn (1–24 giờ) không?</p></li><li><p>Mô hình nào phù hợp với dữ liệu time-series đa biến?</p></li><li><p>Có thể đưa ra khuyến nghị tối ưu hóa dựa trên mô hình không?</p></li></ol>','<h1>9. Phương pháp nghiên cứu</h1><h2>9.1 Tiền xử lý dữ liệu</h2><ul><li><p>Xử lý missing values</p></li><li><p>Outlier detection</p></li><li><p>Chuẩn hóa dữ liệu</p></li></ul><h2>9.2 Feature Engineering</h2><ul><li><p>Lag features (time-series)</p></li><li><p>Moving average</p></li><li><p>Trend extraction</p></li></ul><h2>9.3 Mô hình dự đoán</h2><ul><li><p>Linear Regression</p></li><li><p>Random Forest</p></li><li><p>XGBoost</p></li><li><p>LSTM (time-series deep learning)</p></li></ul>','Đối tượng\n\nDữ liệu chất lượng không khí tại đô thị\n\nPhạm vi\nDữ liệu từ các trạm cảm biến\nThời gian: 2020–2026\nKhu vực: mô phỏng hoặc dữ liệu công khai\nChỉ số: AQI, PM2.5, PM10','<p>Bài báo</p>','<p>Sáng chế</p>',NULL,NULL,NULL,12,10000000.00,'2026-04-16 23:13:32','REVISION_REQUIRED',2,10,2,5,0),(12,'TOPIC-355FEFB1','Nghiên cứu và phát triển hệ thống hỗ trợ chẩn đoán sớm bệnh tim mạch dựa trên dữ liệu lâm sàng và mô hình học máy','Development of a Machine Learning-Based Clinical Decision Support System for Early Cardiovascular Disease Diagnosis','BASIC','Công nghệ thông tin và Trí tuệ nhân tạo','--- GIẢI TRÌNH CHỈNH SỬA ---\nBổ sung thêm thông tin phương pháp nhiên cứu theo yêu cầu của văn phòng khoa.\n\n--- NỘI DUNG ---\n<p>Bệnh tim mạch là một trong những nguyên nhân gây tử vong hàng đầu trên thế giới và tại Việt Nam. Việc phát hiện sớm bệnh có vai trò cực kỳ quan trọng trong việc giảm tỷ lệ tử vong và chi phí điều trị. Tuy nhiên, quy trình chẩn đoán hiện nay vẫn phụ thuộc nhiều vào bác sĩ chuyên môn và các xét nghiệm chuyên sâu, dẫn đến chi phí cao và thời gian xử lý kéo dài.</p><p></p>','<p>Xây dựng hệ thống hỗ trợ chẩn đoán sớm bệnh tim mạch dựa trên dữ liệu lâm sàng và mô hình học máy.</p>','<ul><li><p>Thu thập và chuẩn hóa dữ liệu bệnh nhân</p></li><li><p>Phân tích các yếu tố nguy cơ bệnh tim</p></li><li><p>Xây dựng mô hình dự đoán nguy cơ</p></li><li><p>Đánh giá hiệu năng mô hình</p></li><li><p>Phát triển giao diện demo hệ thống</p></li></ul>','<ul><li><p>Những yếu tố nào ảnh hưởng lớn nhất đến nguy cơ bệnh tim mạch?</p></li><li><p>Mô hình học máy nào phù hợp nhất với dữ liệu y tế dạng bảng?</p></li><li><p>Có thể đạt độ chính xác cao với dữ liệu lâm sàng đơn giản không?</p></li><li><p>Hệ thống có thể hỗ trợ bác sĩ trong thực tế hay không?</p></li></ul>','<ul><li><p>Phân tích dữ liệu (EDA)</p></li><li><p>Tiền xử lý dữ liệu y tế</p></li><li><p>Chuẩn hóa và mã hóa dữ liệu</p></li><li><p>Xây dựng mô hình:</p><ul><li><p>Logistic Regression</p></li><li><p>Decision Tree</p></li><li><p>Random Forest</p></li><li><p>Gradient Boosting</p></li><li><p>SVM</p></li><li><p>CNN</p></li></ul></li></ul>','Đối tượng:\nBệnh nhân có nguy cơ mắc bệnh tim mạch\n\nPhạm vi:\n\nDữ liệu từ 2015 – 2025\nDữ liệu dạng bảng (structured data)\nKhông sử dụng ảnh y tế (MRI, CT)','<p>Báo cáo</p>','<p>Mô hình dự đoán bệnh tim</p>',NULL,NULL,NULL,12,10000000.00,'2026-04-16 23:48:15','PENDING_COUNCIL',2,10,2,6,1),(13,'TOPIC-8AD743BB','Xây dựng hệ thống đánh giá rủi ro doanh nghiệp dựa trên phân tích ngữ nghĩa từ tin tức, mạng xã hội và báo cáo tài chính bằng mô hình AI đa nguồn (Multimodal AI)','Multimodal AI System for Corporate Risk Assessment using Financial Data, News, and Social Media Sentiment','APPLIED','Kinh tế và Quản trị','--- GIẢI TRÌNH CHỈNH SỬA ---\nBỔ SUNG NỘI DUNG CÒN THIẾU THEO YÊU CẦU CỦA PHÒNG QUẢN LÝ KHOA HỌC\n\n--- NỘI DUNG ---\n--- GIẢI TRÌNH CHỈNH SỬA ---\nĐã bổ sung tệp thuyết minh đề tài vào trong hồ sơ đề tài.\n\n--- NỘI DUNG ---\n<p>Trong bối cảnh chuyển đổi số mạnh mẽ, việc đánh giá rủi ro doanh nghiệp đóng vai trò quan trọng trong các hoạt động tín dụng, đầu tư và quản trị tài chính. Tuy nhiên, tại Việt Nam, các phương pháp đánh giá hiện nay chủ yếu dựa trên:</p><ul><li><p>Dữ liệu tài chính truyền thống (structured data)</p></li><li><p>Mô hình thống kê đơn giản</p></li><li><p>Đánh giá thủ công từ chuyên gia</p></li></ul><p></p>','<p>Xây dựng hệ thống trí tuệ nhân tạo đa nguồn (multimodal AI) nhằm đánh giá rủi ro doanh nghiệp dựa trên dữ liệu tài chính kết hợp với dữ liệu văn bản từ tin tức và mạng xã hội.</p>','<ul><li><p>Xây dựng bộ dữ liệu tích hợp:</p><ul><li><p>Dữ liệu tài chính doanh nghiệp</p></li><li><p>Tin tức liên quan</p></li><li><p>Dữ liệu mạng xã hội</p></li></ul></li><li><p>Phát triển pipeline xử lý dữ liệu:</p><ul><li><p>Làm sạch dữ liệu</p></li><li><p>Chuẩn hóa</p></li><li><p>Trích xuất đặc trưng</p></li></ul></li><li><p>Áp dụng các mô hình:</p><ul><li><p>Machine Learning truyền thống (Random Forest, XGBoost)</p></li><li><p>NLP (TF-IDF, Word Embedding, PhoBERT)</p></li></ul></li><li><p>Xây dựng mô hình kết hợp đa nguồn dữ liệu</p></li></ul>','<ol><li><p><strong>Tiếp cận dữ liệu đa chiều</strong></p><ul><li><p>Kết hợp dữ liệu định lượng (tài chính)</p></li><li><p>Và dữ liệu định tính (tin tức, sentiment)</p></li></ul></li><li><p><strong>Tiếp cận theo pipeline Data Science</strong></p><ul><li><p>Thu thập → Tiền xử lý → Feature Engineering → Modeling → Evaluation → Deployment</p></li></ul></li><li><p><strong>Tiếp cận mô hình hóa hiện đại</strong></p><ul><li><p>Sử dụng NLP để chuyển đổi văn bản thành vector</p></li><li><p>Kết hợp với dữ liệu structured để huấn luyện mô hình</p></li></ul></li></ol>','<h2>1. Phương pháp thu thập dữ liệu</h2><ul><li><p>Thu thập báo cáo tài chính từ nguồn công khai</p></li><li><p>Crawl dữ liệu tin tức</p></li><li><p>Thu thập dữ liệu mạng xã hội (Facebook, forum, v.v.)</p></li></ul><hr><h2>2. Phương pháp xử lý dữ liệu</h2><ul><li><p>Xử lý missing values</p></li><li><p>Chuẩn hóa dữ liệu</p></li><li><p>Xử lý văn bản:</p><ul><li><p>Tokenization</p></li><li><p>Stopword removal</p></li><li><p>Vectorization</p></li></ul></li></ul><hr><h2>3. Phương pháp xây dựng mô hình</h2><ul><li><p>Supervised Learning (Classification)</p></li><li><p>Các mô hình:</p><ul><li><p>Logistic Regression</p></li><li><p>Random Forest</p></li><li><p>XGBoost</p></li></ul></li><li><p>NLP:</p><ul><li><p>TF-IDF</p></li><li><p>Word Embedding</p></li><li><p>PhoBERT (nâng cao)</p></li></ul></li></ul><hr><h2>4. Phương pháp đánh giá</h2><ul><li><p>Cross-validation</p></li><li><p>Confusion Matrix</p></li><li><p>ROC Curve</p></li><li><p>F1-score</p></li></ul>','1. Đối tượng nghiên cứu\nDoanh nghiệp vừa và nhỏ (SME) tại Việt Nam\nDữ liệu tài chính và dữ liệu văn bản liên quan\n2. Phạm vi nghiên cứu\nThời gian: 2018 – 2025\nSố lượng dữ liệu:\n~10,000 doanh nghiệp\n~100,000 bản tin / bài viết\nKhông bao gồm:\nDữ liệu nội bộ ngân hàng\nDữ liệu nhạy cảm không công khai','<p>Báo cáo khoa học</p>','<p>Mô hình AI dự đoán rủi ro</p>',NULL,NULL,NULL,24,75000000.00,'2026-04-17 00:29:20','PENDING_COUNCIL',4,10,2,7,0),(14,'TOPIC-49022C3D','Ứng dụng mô hình học sâu nhẹ (Lightweight Deep Learning) và ảnh phổ đa kênh trong hệ thống cảnh báo sớm sâu bệnh hại cho mô hình nông nghiệp đô thị thẳng đứng.','Application of Lightweight Deep Learning and Multi-spectral Imaging for Early Pest Detection in Urban Vertical Farming Systems.','APPLIED','Công nghệ thông tin và Trí tuệ nhân tạo','<p>Nông nghiệp đô thị thẳng đứng đang phát triển mạnh nhưng đối mặt với rủi ro bùng phát dịch bệnh trong không gian kín. Việc phát hiện thủ công gây tốn kém và chậm trễ, trong khi các mô hình AI hiện nay quá nặng để chạy trên các thiết bị Edge (cảm biến tại chỗ).</p>','<p>Xây dựng hệ thống giám sát thời gian thực có khả năng tự động nhận diện và cảnh báo sớm sâu bệnh với độ chính xác trên 90%.</p>','<ol><li><p>Thu thập và gắn nhãn bộ dữ liệu ảnh đa phổ cho 5 loại bệnh phổ biến trên rau thủy canh.</p></li><li><p>Tối ưu hóa mô hình CNN theo kiến trúc MobileNetV3 hoặc GhostNet để giảm dung lượng xuống dưới 10MB.</p></li><li><p>Chế tạo thiết bị mẫu tích hợp camera đa phổ và module giao tiếp không dây.</p></li></ol>','<ul><li><p>&nbsp;Tiếp cận theo hướng tích hợp phần cứng và phần mềm (Edge Computing), tập trung vào tối ưu hóa thuật toán để phù hợp với tài nguyên hạn chế.</p></li></ul>','<ul><li><p>Phương pháp thực nghiệm (thí nghiệm tại các farm đô thị), phương pháp phân tích hệ thống và phương pháp mô hình hóa toán học cho mạng Neural.</p></li></ul>','Đối tượng là cây rau xà lách và cà chua trong hệ thống thủy canh. Phạm vi thực hiện tại các khu nông nghiệp công nghệ cao tại TP.HCM.\n','<p>01 Bài báo tạp chí Q2 (Scopus), </p>','<p>01 thiết bị Edge-AI Prototype, 01 bộ cơ sở dữ liệu ảnh đa phổ</p>',NULL,NULL,NULL,12,19000000.00,'2026-04-18 07:45:40','APPROVED',2,10,4,8,0);
